import { useState, useEffect } from "react";

// ─── SEARCH RESULTS PAGE ─────────────────────────────────────────────────────

function SearchResults({ onBook }) {
  const [destinations, setDestinations] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("http://localhost:5000/destinations")
      .then(res => res.json())
      .then(data => {
        console.log("API DATA:", data);
        setDestinations(data);
        setLoading(false);
      })
      .catch(err => console.error(err));
  }, []);

  if (loading) return <h2 style={{ padding: 20 }}>Loading...</h2>;

  return (
    <div style={{ padding: "20px" }}>
      <h2>Explore Destinations 🌍</h2>

      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fill,minmax(250px,1fr))",
        gap: "20px",
        marginTop: "20px"
      }}>
        {destinations.map((d) => (
          <div key={d._id}
            style={{
              background: "#111",
              color: "#fff",
              padding: "15px",
              borderRadius: "10px",
              border: "1px solid #333"
            }}
          >
            <h3>{d.name}</h3>
            <p>{d.description}</p>
            <p><strong>₹{d.price}</strong></p>

            <button
              onClick={() => onBook(d)}
              style={{
                marginTop: "10px",
                padding: "8px 12px",
                background: "#1D9E75",
                border: "none",
                borderRadius: "6px",
                color: "#fff",
                cursor: "pointer"
              }}
            >
              Book Now →
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── SIMPLE BOOKING PAGE ─────────────────────────────────────────────────────

function BookingFlow({ destination, onBack }) {
  const [confirmed, setConfirmed] = useState(false);

  if (confirmed) {
    return (
      <div style={{ padding: 40 }}>
        <h2>🎉 Booking Confirmed!</h2>
        <p>Your trip to <b>{destination.name}</b> is booked.</p>
        <button onClick={onBack}>Back</button>
      </div>
    );
  }

  return (
    <div style={{ padding: 40 }}>
      <h2>Booking: {destination.name}</h2>
      <p>{destination.description}</p>
      <p>Price: ₹{destination.price}</p>

      <button
        onClick={() => setConfirmed(true)}
        style={{
          marginTop: "20px",
          padding: "10px",
          background: "#1D9E75",
          color: "#fff",
          border: "none"
        }}
      >
        Confirm Booking
      </button>

      <br /><br />
      <button onClick={onBack}>← Back</button>
    </div>
  );
}

// ─── MAIN APP ────────────────────────────────────────────────────────────────

export default function App() {
  const [page, setPage] = useState("search");
  const [selected, setSelected] = useState(null);

  const handleBook = (dest) => {
    setSelected(dest);
    setPage("booking");
  };

  const handleBack = () => {
    setPage("search");
    setSelected(null);
  };

  return (
    <div style={{ fontFamily: "Arial", background: "#0a0f0d", minHeight: "100vh" }}>
      <h1 style={{ color: "#1D9E75", padding: 20 }}>Wanderly 🌍</h1>

      {page === "search" && <SearchResults onBook={handleBook} />}
      {page === "booking" && selected && (
        <BookingFlow destination={selected} onBack={handleBack} />
      )}
    </div>
  );
}
